//! Spec-compliance tests: Styles (ISO 29500-1 §17.7)
//!
//! These tests verify our implementation against specific OOXML style
//! constructs. Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode, Mark};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/styles";

// ── helpers ──────────────────────────────────────────────────────────────
/// Get the first text node of a paragraph.
fn first_text_node(p: &stemma::ParagraphNode) -> Option<&stemma::TextNode> {
    p.all_inlines().find_map(|inline| match inline {
        InlineNode::Text(t) => Some(t.as_ref()),
        _ => None,
    })
}

/// Collect all text nodes from a paragraph.
fn text_nodes(p: &stemma::ParagraphNode) -> Vec<&stemma::TextNode> {
    p.all_inlines()
        .filter_map(|inline| match inline {
            InlineNode::Text(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect()
}

fn first_table(doc: &CanonDoc) -> &stemma::TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("document should contain at least one table")
}

// ── docDefaults (§17.7.4.17) ────────────────────────────────────────────

/// ISO 29500-1 §17.7.4.17: Document defaults provide base run properties.
/// When no style overrides a property, docDefaults values apply.
#[test]
fn spec_style_doc_defaults_font_and_size() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "doc-defaults");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "should have at least 2 paragraphs, got {}",
        paras.len()
    );

    // First paragraph: no style override, should get docDefaults font=Georgia, size=28
    let tn = first_text_node(paras[0]).expect("paragraph 1 should have text");
    assert_eq!(
        tn.style_props.font_family.as_deref(),
        Some("Georgia"),
        "para 1 font should be Georgia from docDefaults"
    );
    assert_eq!(
        tn.style_props.font_size,
        Some(28),
        "para 1 size should be 28 half-points (14pt) from docDefaults"
    );
    assert_eq!(
        tn.style_props.color.as_deref(),
        Some("333333"),
        "para 1 color should be 333333 from docDefaults"
    );
}

/// ISO 29500-1 §17.7.4.17: Style overrides docDefaults for font but inherits size.
#[test]
fn spec_style_doc_defaults_partial_override() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "doc-defaults");
    let paras = common::all_paragraphs(&doc);
    assert!(paras.len() >= 2, "should have at least 2 paragraphs");

    // Second paragraph: FontOverride style sets font=Courier New, but size/color from docDefaults
    let tn = first_text_node(paras[1]).expect("paragraph 2 should have text");
    assert_eq!(
        tn.style_props.font_family.as_deref(),
        Some("Courier New"),
        "para 2 font should be Courier New from style override"
    );
    assert_eq!(
        tn.style_props.font_size,
        Some(28),
        "para 2 size should be 28 from docDefaults (not overridden by style)"
    );
    assert_eq!(
        tn.style_props.color.as_deref(),
        Some("333333"),
        "para 2 color should be 333333 from docDefaults (not overridden by style)"
    );
}

/// ISO 29500-1 §17.7.4.17: pPrDefault spacing should be exposed.
#[test]
fn spec_style_doc_defaults_paragraph_spacing() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "doc-defaults");
    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty());

    // First paragraph should inherit pPrDefault spacing: after=200, line=276
    let spacing = paras[0]
        .spacing
        .as_ref()
        .expect("paragraph 1 should have spacing from pPrDefault");
    assert_eq!(
        spacing.after,
        Some(200),
        "pPrDefault spacing.after should be 200"
    );
    assert_eq!(
        spacing.line,
        Some(276),
        "pPrDefault spacing.line should be 276"
    );
}

// ── basedOn chain (§17.7.4.3) ───────────────────────────────────────────

/// ISO 29500-1 §17.7.4.3: Three-level basedOn chain C->B->A.
/// Style C: adds italic + font=Arial.  Style B: adds bold + size=28.  Style A: font=TNR + size=24.
/// Effective for C: Arial (C), 28 (B), bold (B), italic (C).
#[test]
fn spec_style_based_on_chain_cascading() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "based-on-chain");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "should have at least 2 paragraphs, got {}",
        paras.len()
    );

    // Find paragraph with StyleC
    let p_c = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Style C"))
        .expect("should find StyleC paragraph");

    let tn = first_text_node(p_c).expect("StyleC paragraph should have text");

    // Font from C (Arial), size from B (28)
    assert_eq!(
        tn.style_props.font_family.as_deref(),
        Some("Arial"),
        "StyleC should get font=Arial from its own definition"
    );
    assert_eq!(
        tn.style_props.font_size,
        Some(28),
        "StyleC should get size=28 from StyleB"
    );

    // Bold from B (toggle), italic from C
    assert!(
        tn.marks.contains(&Mark::Bold),
        "StyleC should inherit bold from StyleB"
    );
    assert!(
        tn.marks.contains(&Mark::Italic),
        "StyleC should have italic from its own definition"
    );
}

/// ISO 29500-1 §17.7.4.3: Baseline style (A) should have its own properties.
#[test]
fn spec_style_based_on_chain_baseline() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "based-on-chain");
    let paras = common::all_paragraphs(&doc);

    let p_a = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Style A"))
        .expect("should find StyleA paragraph");

    let tn = first_text_node(p_a).expect("StyleA paragraph should have text");

    assert_eq!(
        tn.style_props.font_family.as_deref(),
        Some("Times New Roman"),
        "StyleA should have font=Times New Roman"
    );
    assert_eq!(
        tn.style_props.font_size,
        Some(24),
        "StyleA should have size=24"
    );
    assert!(!tn.marks.contains(&Mark::Bold), "StyleA should not be bold");
    assert!(
        !tn.marks.contains(&Mark::Italic),
        "StyleA should not be italic"
    );
}

// ── Character style overrides paragraph style (§17.7.2) ─────────────────

/// ISO 29500-1 §17.7.2: Run with no char style gets paragraph style properties.
#[test]
fn spec_style_cascade_para_only() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "char-overrides-para");
    let paras = common::all_paragraphs(&doc);

    // Find the paragraph using RedItalicPara
    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Para style only"))
        .expect("should find test paragraph");

    let nodes = text_nodes(p);
    let run1 = nodes
        .iter()
        .find(|n| n.text.contains("Para style only"))
        .expect("should find run 1");

    assert!(
        run1.marks.contains(&Mark::Italic),
        "run 1 should be italic from para style"
    );
    assert_eq!(
        run1.style_props.color.as_deref(),
        Some("FF0000"),
        "run 1 color should be FF0000 from para style"
    );
}

/// ISO 29500-1 §17.7.2: Character style overrides paragraph style for non-toggle props.
#[test]
fn spec_style_cascade_char_overrides() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "char-overrides-para");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Char style overrides"))
        .expect("should find test paragraph");

    let nodes = text_nodes(p);
    let run2 = nodes
        .iter()
        .find(|n| n.text.contains("Char style overrides"))
        .expect("should find run 2");

    // Color should come from char style (0000FF), not para style (FF0000)
    assert_eq!(
        run2.style_props.color.as_deref(),
        Some("0000FF"),
        "run 2 color should be 0000FF from char style, overriding para style"
    );

    // Bold should come from char style
    assert!(
        run2.marks.contains(&Mark::Bold),
        "run 2 should be bold from char style"
    );
}

/// ISO 29500-1 §17.7.2: Direct formatting overrides both char and para style.
#[test]
fn spec_style_cascade_direct_overrides() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "char-overrides-para");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Direct override"))
        .expect("should find test paragraph");

    let nodes = text_nodes(p);
    let run3 = nodes
        .iter()
        .find(|n| n.text.contains("Direct override"))
        .expect("should find run 3");

    assert_eq!(
        run3.style_props.color.as_deref(),
        Some("00FF00"),
        "run 3 color should be 00FF00 from direct formatting"
    );
}

// ── Toggle property XOR (§17.7.3) ───────────────────────────────────────

/// MS-OI29500 §2.1.258: Para bold=true + char bold=true -> char overrides -> bold=true.
/// (Previously tested ECMA XOR which gave bold=false, but Word uses reset semantics.)
#[test]
fn spec_style_toggle_xor_both_on() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-xor-hierarchy");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("XOR false"))
        .expect("should find XOR test paragraph");

    let nodes = text_nodes(p);
    let run1 = nodes
        .iter()
        .find(|n| n.text.contains("XOR false"))
        .expect("should find run 1");

    // MS-OI29500 §2.1.258: char style bold=on overrides para style bold=on → bold=ON.
    assert!(
        run1.marks.contains(&Mark::Bold),
        "char bold=on overrides para bold=on → bold=on (MS-OI29500 §2.1.258 reset semantics)"
    );
}

/// ISO 29500-1 §17.7.3: Para bold=true, no char style -> effective bold=true.
#[test]
fn spec_style_toggle_para_only() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-xor-hierarchy");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Para bold only"))
        .expect("should find para-only test paragraph");

    let nodes = text_nodes(p);
    let run2 = nodes
        .iter()
        .find(|n| n.text.contains("Para bold only"))
        .expect("should find run 2");

    assert!(
        run2.marks.contains(&Mark::Bold),
        "para bold without char style should be bold=on"
    );
}

/// MS-OI29500 §2.1.258: Para bold=true + char bold=false -> char overrides -> bold=false.
/// (Previously tested ECMA XOR which gave bold=true, but Word uses reset semantics.)
#[test]
fn spec_style_toggle_xor_on_off() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-xor-hierarchy");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("XOR true"))
        .expect("should find XOR true test paragraph");

    let nodes = text_nodes(p);
    let run3 = nodes
        .iter()
        .find(|n| n.text.contains("XOR true"))
        .expect("should find run 3");

    // MS-OI29500 §2.1.258: char style bold=off overrides para style bold=on → bold=OFF.
    assert!(
        !run3.marks.contains(&Mark::Bold),
        "char bold=off overrides para bold=on → bold=off (MS-OI29500 §2.1.258 reset semantics)"
    );
}

// ── Normal default style (§17.7.4.17) ───────────────────────────────────

/// ISO 29500-1 §17.7.4.17: Unstyled paragraphs get Normal style properties.
#[test]
fn spec_style_normal_default_font() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "normal-default");
    let paras = common::all_paragraphs(&doc);
    assert!(paras.len() >= 2, "should have at least 2 paragraphs");

    // Both paragraphs should have Calibri 22 from Normal style
    for (idx, p) in paras.iter().enumerate() {
        let tn = first_text_node(p).unwrap_or_else(|| panic!("paragraph {idx} should have text"));
        assert_eq!(
            tn.style_props.font_family.as_deref(),
            Some("Calibri"),
            "paragraph {idx} font should be Calibri from Normal style"
        );
        assert_eq!(
            tn.style_props.font_size,
            Some(22),
            "paragraph {idx} size should be 22 from Normal style"
        );
    }
}

/// ISO 29500-1 §17.7.4.17: Normal style alignment should be applied.
#[test]
fn spec_style_normal_default_alignment() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "normal-default");
    let paras = common::all_paragraphs(&doc);

    // First paragraph (unstyled) should get alignment from Normal
    let p1 = &paras[0];
    assert_eq!(
        p1.align,
        Some(stemma::Alignment::Justify),
        "unstyled paragraph should get justify alignment from Normal style"
    );
}

// ── Table style with conditional formatting (§17.7.6) ───────────────────

/// ISO 29500-1 §17.7.6: Table style borders should be resolved.
#[test]
fn spec_style_table_conditional_borders() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "table-conditional");
    let table = first_table(&doc);

    let borders = table
        .formatting
        .borders
        .as_ref()
        .expect("table should have borders from ConditionalTable style");

    // ConditionalTable defines single/4pt/999999 borders on all edges.
    assert_eq!(
        borders.top.as_ref().unwrap().style,
        stemma::domain::BorderStyle::Single,
        "table top border should be single from style"
    );
    assert_eq!(
        borders.top.as_ref().unwrap().color.as_deref(),
        Some("999999"),
        "table border color should be 999999 from style"
    );
}

/// ISO 29500-1 §17.7.6: Conditional formatting firstRow applies cell shading.
#[test]
fn spec_style_table_conditional_first_row_shading() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "table-conditional");
    let table = first_table(&doc);

    // First row cells should have blue shading (fill=4472C4) from firstRow conditional
    let cell_0_0 = &table.rows[0].cells[0];
    let shading = cell_0_0
        .formatting
        .shading
        .as_ref()
        .expect("first row cell should have shading from firstRow conditional");
    assert_eq!(
        shading.fill.as_deref(),
        Some("4472C4"),
        "first row cell fill should be 4472C4 from firstRow conditional"
    );
}

/// ISO 29500-1 §17.7.6: Band row shading from conditional formatting.
#[test]
fn spec_style_table_conditional_band_shading() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "table-conditional");
    let table = first_table(&doc);

    // Row 1 (first data row after header): the style has band1Horz conditionals
    // but NO tblStyleRowBandSize. Per MS-OI29500 §17.7.6.7, band size defaults
    // to 0 when absent → no banding is applied.
    // The cell may still have shading from the style's default tcPr (fill="auto"),
    // but it should NOT have the band1Horz fill (D9E2F3).
    let cell_1_0 = &table.rows[1].cells[0];
    if let Some(shading) = &cell_1_0.formatting.shading {
        assert_ne!(
            shading.fill.as_deref(),
            Some("D9E2F3"),
            "band1 row cell should NOT have band1Horz fill — band size absent (MS default 0)"
        );
    }
    // If shading is None, that's also correct — no banding was applied.
}

// ── Style-based numbering (§17.7.4.14) ──────────────────────────────────

/// ISO 29500-1 §17.7.4.14: Paragraph style with numPr provides numbering.
#[test]
fn spec_style_numbering_from_style() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "numbering-from-style");
    let paras = common::all_paragraphs(&doc);

    // Find paragraphs with "clause" text — they use the NumberedClause style
    let clause_paras: Vec<&&stemma::ParagraphNode> = paras
        .iter()
        .filter(|p| common::paragraph_text(p).contains("clause"))
        .collect();

    assert!(
        clause_paras.len() >= 3,
        "should find at least 3 clause paragraphs, got {}",
        clause_paras.len()
    );

    // Each clause paragraph should have numbering info
    for (idx, p) in clause_paras.iter().enumerate() {
        assert!(
            p.numbering.is_some(),
            "clause paragraph {} should have numbering info from style numPr",
            idx + 1
        );
    }
}

/// ISO 29500-1 §17.7.4.14: Style-based numbering should synthesize sequential numbers.
#[test]
fn spec_style_numbering_sequential() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "numbering-from-style");
    let paras = common::all_paragraphs(&doc);

    let clause_paras: Vec<&&stemma::ParagraphNode> = paras
        .iter()
        .filter(|p| common::paragraph_text(p).contains("clause"))
        .collect();

    if clause_paras.len() >= 3 {
        // Check that synthesized text increments: "1.", "2.", "3."
        let num1 = clause_paras[0]
            .numbering
            .as_ref()
            .expect("clause 1 numbering");
        let num2 = clause_paras[1]
            .numbering
            .as_ref()
            .expect("clause 2 numbering");
        let num3 = clause_paras[2]
            .numbering
            .as_ref()
            .expect("clause 3 numbering");

        assert_eq!(num1.synthesized_text, "1.", "first clause should be 1.");
        assert_eq!(num2.synthesized_text, "2.", "second clause should be 2.");
        assert_eq!(num3.synthesized_text, "3.", "third clause should be 3.");
    }
}

// ── Linked styles (§17.7.4.6) ───────────────────────────────────────────

/// ISO 29500-1 §17.7.4.6: Paragraph with LinkedPara style gets run properties.
#[test]
fn spec_style_linked_para_run_props() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "linked-styles");
    let paras = common::all_paragraphs(&doc);

    let p1 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("LinkedPara style"))
        .expect("should find LinkedPara paragraph");

    let tn = first_text_node(p1).expect("LinkedPara paragraph should have text");

    assert!(
        tn.marks.contains(&Mark::Bold),
        "LinkedPara should produce bold"
    );
    assert_eq!(
        tn.style_props.font_size,
        Some(32),
        "LinkedPara should produce size=32"
    );
    assert_eq!(
        tn.style_props.color.as_deref(),
        Some("2E74B5"),
        "LinkedPara should produce color=2E74B5"
    );
}

