/// ISO 29500-1 §17.7.4.6: Run with linked character style gets char style properties.
#[test]
fn spec_style_linked_char_run_props() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "linked-styles");
    let paras = common::all_paragraphs(&doc);

    let p2 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Normal text"))
        .expect("should find paragraph with LinkedChar run");

    let nodes = text_nodes(p2);
    let linked_run = nodes
        .iter()
        .find(|n| n.text.contains("LinkedChar"))
        .expect("should find run with LinkedChar style");

    assert!(
        linked_run.marks.contains(&Mark::Bold),
        "LinkedChar run should be bold"
    );
    assert_eq!(
        linked_run.style_props.font_size,
        Some(32),
        "LinkedChar run should have size=32"
    );
    assert_eq!(
        linked_run.style_props.color.as_deref(),
        Some("2E74B5"),
        "LinkedChar run should have color=2E74B5"
    );
}
